import{_ as e,o as r,c as a,ae as d}from"./chunks/framework.DrYEjkpc.js";const y=JSON.parse('{"title":"Skills 技术成熟度评估模型","description":"","frontmatter":{},"headers":[],"relativePath":"radar/03-maturity.md","filePath":"radar/03-maturity.md"}'),l={name:"radar/03-maturity.md"};function n(s,t,i,o,h,g){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="skills-技术成熟度评估模型" tabindex="-1">Skills 技术成熟度评估模型 <a class="header-anchor" href="#skills-技术成熟度评估模型" aria-label="Permalink to &quot;Skills 技术成熟度评估模型&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v2.0 · <strong>更新日期</strong>: 2026-05-12</p></blockquote><hr><h2 id="一、评估维度" tabindex="-1">一、评估维度 <a class="header-anchor" href="#一、评估维度" aria-label="Permalink to &quot;一、评估维度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>描述</th><th style="text-align:center;">权重</th></tr></thead><tbody><tr><td><strong>技术成熟度</strong></td><td>从论文实验到生产部署的演进程度</td><td style="text-align:center;">30%</td></tr><tr><td><strong>创新性</strong></td><td>相对现有路径的原创性和方法论突破</td><td style="text-align:center;">25%</td></tr><tr><td><strong>落地程度</strong></td><td>在真实产品 / 项目 / 企业场景中的应用广度</td><td style="text-align:center;">25%</td></tr><tr><td><strong>生态活跃度</strong></td><td>GitHub Star · 引用 · 贡献者 · 商业生态</td><td style="text-align:center;">20%</td></tr></tbody></table><p><strong>综合评分公式</strong>：<code>overall = 0.30 × maturity + 0.25 × innovation + 0.25 × adoption + 0.20 × ecosystem</code></p><hr><h2 id="二、成熟度等级定义" tabindex="-1">二、成熟度等级定义 <a class="header-anchor" href="#二、成熟度等级定义" aria-label="Permalink to &quot;二、成熟度等级定义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>等级</th><th style="text-align:center;">标签</th><th style="text-align:center;">综合评分</th><th>典型特征</th></tr></thead><tbody><tr><td><strong>探索期</strong></td><td style="text-align:center;">🔴</td><td style="text-align:center;">&lt; 0.40</td><td>痛点已被研究但缺少有效方案；仅论文或早期原型</td></tr><tr><td><strong>成长期</strong></td><td style="text-align:center;">🟡</td><td style="text-align:center;">0.40 – 0.60</td><td>有原型实现，开始落地应用；多个开源项目</td></tr><tr><td><strong>成熟期</strong></td><td style="text-align:center;">🟢</td><td style="text-align:center;">≥ 0.60</td><td>有可工程化部署的方案，大规模实际应用</td></tr></tbody></table><hr><h2 id="三、4-维评分细则" tabindex="-1">三、4 维评分细则 <a class="header-anchor" href="#三、4-维评分细则" aria-label="Permalink to &quot;三、4 维评分细则&quot;">​</a></h2><h3 id="_3-1-技术成熟度" tabindex="-1">3.1 技术成熟度 <a class="header-anchor" href="#_3-1-技术成熟度" aria-label="Permalink to &quot;3.1 技术成熟度&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">分数</th><th>阶段</th></tr></thead><tbody><tr><td style="text-align:center;">0.00 - 0.45</td><td>论文阶段，无开源实现</td></tr><tr><td style="text-align:center;">0.45 - 0.65</td><td>论文 + 开源实现</td></tr><tr><td style="text-align:center;">0.65 - 0.80</td><td>论文 + 开源 + 工业验证</td></tr><tr><td style="text-align:center;">0.80 - 1.00</td><td>标准 / 大规模生产部署</td></tr></tbody></table><h3 id="_3-2-创新性" tabindex="-1">3.2 创新性 <a class="header-anchor" href="#_3-2-创新性" aria-label="Permalink to &quot;3.2 创新性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">分数</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">0.00 - 0.45</td><td>渐进改进，无原创性突破</td></tr><tr><td style="text-align:center;">0.45 - 0.65</td><td>有一定方法论创新</td></tr><tr><td style="text-align:center;">0.65 - 0.80</td><td>显著创新，被业界引用</td></tr><tr><td style="text-align:center;">0.80 - 1.00</td><td>范式级突破，引领方向</td></tr></tbody></table><h3 id="_3-3-落地程度" tabindex="-1">3.3 落地程度 <a class="header-anchor" href="#_3-3-落地程度" aria-label="Permalink to &quot;3.3 落地程度&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">分数</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">0.00 - 0.35</td><td>仅学术实验或闭源内部使用</td></tr><tr><td style="text-align:center;">0.35 - 0.55</td><td>小范围试点、社区早期采用</td></tr><tr><td style="text-align:center;">0.55 - 0.75</td><td>多个实际产品采用</td></tr><tr><td style="text-align:center;">0.75 - 1.00</td><td>官方标准 / 行业广泛部署</td></tr></tbody></table><h3 id="_3-4-生态活跃度" tabindex="-1">3.4 生态活跃度 <a class="header-anchor" href="#_3-4-生态活跃度" aria-label="Permalink to &quot;3.4 生态活跃度&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">分数</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">0.00 - 0.40</td><td>无社区或论文阶段，少量更新</td></tr><tr><td style="text-align:center;">0.40 - 0.60</td><td>中等社区、稳定维护</td></tr><tr><td style="text-align:center;">0.60 - 0.80</td><td>活跃社区、高频更新</td></tr><tr><td style="text-align:center;">0.80 - 1.00</td><td>重量级生态（如 4K+ ★、官方背书）</td></tr></tbody></table><hr><h2 id="四、categorysummary-的特殊计算" tabindex="-1">四、categorySummary 的特殊计算 <a class="header-anchor" href="#四、categorysummary-的特殊计算" aria-label="Permalink to &quot;四、categorySummary 的特殊计算&quot;">​</a></h2><p>每个 category 的综合分<strong>不机械平均所有产品</strong>，而是综合考虑：</p><ol><li>该 category 下产品数量及典型代表的评分</li><li><strong>业界核心痛点的解决程度</strong>（参考 Skill-insight 竞品分析中的 🟢🟡🔴⚪ 证据分类）</li><li><strong>是否存在结构性空白</strong>（如管理阶段的&quot;防御工具为零&quot;会显著拉低评分）</li></ol><table tabindex="0"><thead><tr><th>阶段</th><th style="text-align:center;">综合评分</th><th style="text-align:center;">等级</th></tr></thead><tbody><tr><td>Skill 召回</td><td style="text-align:center;"><strong>0.65</strong></td><td style="text-align:center;">🟢 成熟期</td></tr><tr><td>Skill 优化</td><td style="text-align:center;"><strong>0.59</strong></td><td style="text-align:center;">🟡 成长期</td></tr><tr><td>Skill 生成</td><td style="text-align:center;"><strong>0.55</strong></td><td style="text-align:center;">🟡 成长期</td></tr><tr><td>Skill 评测</td><td style="text-align:center;"><strong>0.47</strong></td><td style="text-align:center;">🟡 成长期</td></tr><tr><td>Skill 执行</td><td style="text-align:center;"><strong>0.45</strong></td><td style="text-align:center;">🟡 成长期</td></tr><tr><td>Skill 管理</td><td style="text-align:center;"><strong>0.40</strong></td><td style="text-align:center;">🟡 成长期（边界）</td></tr></tbody></table><hr><h2 id="五、数据来源" tabindex="-1">五、数据来源 <a class="header-anchor" href="#五、数据来源" aria-label="Permalink to &quot;五、数据来源&quot;">​</a></h2><ul><li>原始数据：<a href="../assets/radar-data.json">radar-data.json</a></li><li>每个产品的 4 维评分依据：各 <a href="./01-taxonomy.html">tech-*.md 详情页</a> 末尾的&quot;成熟度评分&quot;小节</li></ul>',27)])])}const x=e(l,[["render",n]]);export{y as __pageData,x as default};
